// ===== WF-ANALYZER Chang 1: Doc file raw + parse co ban =====
// Muc tieu: xac nhan n8n DOC DUOC file pfsense.log do collector ghi,
// tach timestamp + raw, phan loai nguon log. CHUA dem nguong (chang sau).

// Node "Extract from File" da chuyen noi dung file -> $json.data (text)
const content = $input.first().json.data || '';
const lines = content.split('\n').filter(l => l.trim());

// Dem theo nguon log (de biet co du lieu gi)
const counts = { filterlog: 0, auth: 0, suricata: 0, dhcp: 0, other: 0 };
const parsed = [];

for (const line of lines) {
  // Tach timestamp thu nhan (collector ghi dau dong, ngan cach TAB) + raw
  let ts = null, raw = line;
  const tabIdx = line.indexOf('\t');
  if (tabIdx >= 0) {
    ts = line.slice(0, tabIdx);
    raw = line.slice(tabIdx + 1);
  }

  // Phan loai nguon log
  const low = raw.toLowerCase();
  let source = 'other';
  if (low.includes('filterlog')) source = 'filterlog';
  else if (low.includes('failed password') || low.includes('invalid user')) source = 'auth';
  else if (raw.includes('[**]')) source = 'suricata';
  else if (low.includes('dhcp')) source = 'dhcp';
  counts[source]++;

  parsed.push({ ts, source, raw });
}

// Tra ve tong quan + 10 dong cuoi de kiem tra
return [{ json: {
  total_lines: lines.length,
  counts: counts,
  sample_last_10: parsed.slice(-10),
}}];
